import PropTypes from 'prop-types';

import Alert from '@mui/material/Alert';
import Box from '@mui/material/Box';
import CircularProgress from '@mui/material/CircularProgress';
import Stack from '@mui/material/Stack';
import Typography from '@mui/material/Typography';

export function LoadingState({ message = 'Cargando...' }) {
  return (
    <Stack sx={{ alignItems: 'center', py: 7, gap: 2 }}>
      <CircularProgress size={30} />
      <Typography variant="body2" color="text.secondary">
        {message}
      </Typography>
    </Stack>
  );
}

LoadingState.propTypes = {
  message: PropTypes.string
};

export function EmptyState({ message = 'No hay datos para mostrar.' }) {
  return (
    <Stack sx={{ alignItems: 'center', py: 7, gap: 1 }}>
      <Box sx={{ width: 44, height: 44, borderRadius: '50%', bgcolor: 'grey.100' }} />
      <Typography variant="body2" color="text.secondary">
        {message}
      </Typography>
    </Stack>
  );
}

EmptyState.propTypes = {
  message: PropTypes.string
};

export function ErrorState({ message = 'Ocurrio un error al cargar los datos.' }) {
  return (
    <Alert severity="error" sx={{ mb: 2, borderRadius: 2 }}>
      {message}
    </Alert>
  );
}

ErrorState.propTypes = {
  message: PropTypes.string
};
